1	export interface QuoteInput {
2	  customer?: { yearsWithMHPCO: number };
3	  items: { type: string; cursed?: boolean; enchantment?: number }[];
4	}
5	
6	const PROCESSING_FEE = 5;
7	
8	const BLOCK_SIZE = 3;
9	const BLOCK_PRICE = 60;
10	
11	const CURSE_SURCHARGE_RATE = 0.5;
12	
13	const HIGH_ENCHANTMENT_THRESHOLD = 5;
14	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
15	
16	const BASE_PREMIUMS: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	
25	export function quote(input: QuoteInput): number {
26	  const countsByType: Record<string, number> = {};
27	  for (const item of input.items) {
28	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
29	  }
30	
31	  let basePremiumTotal = 0;
32	  for (const type of Object.keys(countsByType)) {
33	    const count = countsByType[type];
34	    if (count === BLOCK_SIZE) {
35	      basePremiumTotal += BLOCK_PRICE;
36	    } else {
37	      basePremiumTotal += count * BASE_PREMIUMS[type];
38	    }
39	  }
40	
41	  let surchargeTotal = 0;
42	  for (const item of input.items) {
43	    if (item.cursed) {
44	      surchargeTotal += BASE_PREMIUMS[item.type] * CURSE_SURCHARGE_RATE;
45	    }
46	    if (
47	      item.enchantment !== undefined &&
48	      item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD
49	    ) {
50	      surchargeTotal +=
51	        BASE_PREMIUMS[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE;
52	    }
53	  }
54	
55	  let loyaltyDiscount = 0;
56	  if (input.customer !== undefined && input.customer.yearsWithMHPCO >= 2) {
57	    loyaltyDiscount = basePremiumTotal * 0.2;
58	  }
59	
60	  return basePremiumTotal - loyaltyDiscount + surchargeTotal + PROCESSING_FEE;
61	}
62	
63	export function claim(): number {
64	  return undefined as unknown as number;
65	}
